#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N, X; scanf("%lld %lld", &N, &X);
        long long sum = 0, val;
        for(int i=0;i<N-1;i++){
            scanf("%lld", &val);
            sum += val;
        }
        long long need = N * X - sum;
        if(need < 0) need = 0;
        printf("%lld\n", need);
    }
    return 0;
}

