import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); X = int(next(it))
        sum_vals = 0
        for _ in range(N-1):
            sum_vals += int(next(it))
        need = N * X - sum_vals
        if need < 0:
            need = 0
        out.append(str(need))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

